class Solution {
    public int strongPasswordChecker(String password) {
        int n = password.length();
        boolean hasLower = false, hasUpper = false, hasDigit = false;
        for (char c : password.toCharArray()) {
            if (c >= 'a' && c <= 'z') hasLower = true;
            else if (c >= 'A' && c <= 'Z') hasUpper = true;
            else if (c >= '0' && c <= '9') hasDigit = true;
        }
        int missingTypes = 0;
        if (!hasLower) missingTypes++;
        if (!hasUpper) missingTypes++;
        if (!hasDigit) missingTypes++;

        if (n < 6) {
            return Math.max(6 - n, missingTypes);
        }

        int replace = 0, one = 0, two = 0;
        for (int i = 2; i < n; ) {
            if (password.charAt(i) == password.charAt(i - 1) && password.charAt(i - 1) == password.charAt(i - 2)) {
                int len = 2;
                while (i < n && password.charAt(i) == password.charAt(i - 1)) {
                    len++;
                    i++;
                }
                replace += len / 3;
                if (len % 3 == 0) one++;
                else if (len % 3 == 1) two++;
            } else {
                i++;
            }
        }

        if (n <= 20) {
            return Math.max(replace, missingTypes);
        }

        int delete = n - 20;
        replace -= Math.min(delete, one * 1) / 1;
        replace -= Math.min(Math.max(delete - one, 0), two * 2) / 2;
        replace -= Math.max(delete - one - 2 * two, 0) / 3;
        return delete + Math.max(replace, missingTypes);
    }
}
